mapper.select:
SELECT 
    /* 1. 총 회원 (마스터 제외, 활동중인 유저) */
    (SELECT COUNT(*) FROM MEMBER M
     WHERE M.STATUS = 'Y' AND M.MEM_NO != 0

       AND M.DEPT_NO IN (SELECT DEPT_NO FROM DEPARTMENT WHERE UNI_NO = #{uniNo}) 

    ) AS TOTAL_MEM,

    /* 2. 가입 대기 (STATUS='Y'인데 ROLE_USER 권한이 없는 유저) */
    (SELECT COUNT(*) FROM MEMBER M
     WHERE M.STATUS = 'Y' AND M.MEM_NO != 0
     AND NOT EXISTS (
        SELECT 1 FROM AUTHORITIES A 
        WHERE A.MEM_NO = M.MEM_NO 
        AND A.AUTHORITY = 'ROLE_USER'
     )

       AND M.DEPT_NO IN (SELECT DEPT_NO FROM DEPARTMENT WHERE UNI_NO = #{uniNo}) 

    ) AS PENDING_MEM,

    /* 3. 정지 회원 */
    (SELECT COUNT(*) FROM MEMBER M
     WHERE M.STATUS = 'B'

       AND M.DEPT_NO IN (SELECT DEPT_NO FROM DEPARTMENT WHERE UNI_NO = #{uniNo}) 

    ) AS BANNED_MEM,

    /* 4. 신고 건수 (전체) */
    (SELECT COUNT(*) FROM REPORT) AS REPORT_COUNT,

    /* 5. 게시글 수 */
    (SELECT COUNT(*) FROM BOARD B
     WHERE B.STATUS = 'Y'

       AND B.UBTYPE_NO IN (SELECT UBTYPE_NO FROM UNI_BOARD_TYPE WHERE UNI_NO = #{uniNo}) 

    ) AS BOARD_COUNT,

    /* 6. 학교 수 */
    (SELECT COUNT(*) FROM UNIVERSITY WHERE STATUS = 'Y') AS UNI_COUNT
FROM DUAL

mapper.delete:
DELETE FROM BOARD_LIKE
WHERE BOARD_NO IN (
    SELECT BOARD_NO
    FROM BOARD
    WHERE BOARD_WRITER = #{memNo}
)

DELETE FROM REPLY_LIKE
WHERE REPLY_NO IN (
    SELECT REPLY_NO
    FROM REPLY
    WHERE BOARD_NO IN (
        SELECT BOARD_NO
        FROM BOARD
        WHERE BOARD_WRITER = #{memNo}
    )
)

DELETE FROM REPLY
WHERE BOARD_NO IN (
    SELECT BOARD_NO
    FROM BOARD
    WHERE BOARD_WRITER = #{memNo}
)

DELETE FROM FRIENDS
WHERE SENDER_NO = #{memNo}
   OR RECEIVER_NO = #{memNo}
